// // This module implements a 4-bit shift register with a parallel load function.
// The shift register has two inputs, clk and load, and two outputs, q and q_bar.
// The clk input is the clock signal which is used to synchronize the shift register.
// The load input is a control signal which will load the data from the parallel input, p, into the shift register when it is low.
// The shift register should shift the data in q to the right on every falling edge of the clock signal.
// The q output is the output of the shift register which will be the current value stored in the shift register.
// The q_bar output is the inverse of the q output.
module shift_register (
  input clk,
  input load,
  input [3:0] p,
  output reg [3:0] q,
  output reg [3:0] q_bar
);

  always @(posedge clk) begin
    if (load) begin
      q <= p;
      q_bar <= ~p;
    end else begin
      q <= {q[2:0], 1'b0};
      q_bar <= ~{q[2:0], 1'b0};
    end
  end

endmodule

